import React from 'react';

const StatCard = ({ title, value, icon, color }) => {
  const icons = {
    truck: 'M12 1H2v6h10v6H4v2h8v2h2v-2h4V7h-4V3h-2V1zm0 2v2h2v2h-2v6H6V7h6V3z',
    bell: 'M12 22c1.1 0 2-.9 2-2h-4c0 1.1.9 2 2 2zm6-6v-5c0-3.1-1.6-5.8-4-7.1V3h-4v.9c-2.4 1.3-4 4-4 7.1v5l-2 2v1h12v-1l-2-2z',
    wrench: 'M22 2L9 15l-2-2 13-13-2-2zm-2 4c0 4.4-3.6 8-8 8s-8-3.6-8-8 3.6-8 8-8c1.6 0 3.1.5 4.4 1.3l-2.1 2.1C12.5 5.4 11.3 5 10 5c-3.3 0-6 2.7-6 6s2.7 6 6 6 6-2.7 6-6h4z',
  };

  return (
    <div className={`stat-card flex items-center p-4 ${color} rounded-lg shadow-md`}>
      <svg className="w-8 h-8 mr-4 text-gray-600" fill="currentColor" viewBox="0 0 24 24">
        <path d={icons[icon]} />
      </svg>
      <div>
        <h3 className="text-sm font-medium text-gray-600">{title}</h3>
        <p className="text-2xl font-bold text-gray-900">{value}</p>
      </div>
    </div>
  );
};

export default StatCard;
